{
  "verses": [
    {
      "n": 15,
      "column": "left",
      "text": "Kad nu Waraü̅s scho Lee-\ntu dsirdeja / tad mekleja wiꞥſch\nMohsu nokaut/ un Mohsus beh-\ndse preeſch Waraü̅s/ un palikte\nMidijanas Semmê / un paſeh-\ndehs pee weenas Akkas.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Un tam Midijanas aug-\ntam * Kungam bija ſeptin Mei-\nas/ tahs nahze ſmelt/ un pildija\nahs Uhdens-Stiles / ka tahs fa-\nva Tehwa Awis dsirdinatu.\n"
    },
    {
      "n": 17,
      "column": "left",
      "text": "Tad nahze tee Ganni un\nodſinne tahs / un Mohsus zeh-\nhs/ un iglahbe tahs / un dsirdi-\naja wiꞥno Awis.\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Un kad tahs pee fawa Teh-\na * Reguëta nahze/ tad fazzija\nwiꞥſch : Kapehz effat juhs ſcho-\neen tik drihs nahkufchas ?\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Tad fazzija tahs: Weene\ngiptexu Wihrs irr muhs iglah-\nis no to Gannu Rohkas / uu\nwiꞥſch irr mums arri finchlis/un\nuhfas Awis dsirdinajis.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Un tas fazzija us fa-\nahm Meitahm : Kur tad irr\nwiꞥſch ? Kapehz effat juhs ſcho\nBihru atlaiduschas / aizinajeet\n/ ka tas (ar mums) Maisi ehd.\n"
    },
    {
      "n": 21,
      "column": "left",
      "text": "Un Mohsun gribbejahs\nce ta Wihra mahjoht / un tas\ntwe Mohsum fawn Meitu Zi-\nporu par Seewu.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Ta dſendeja wiꞥnam wee-\nu Dehlu/ un tas noſauze wiꞥza\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Wahrdu Gersons/ jo ta fazzija\nwiꞥſch: Es efimu Sweschineek-\ntappis Sweschâ Semmê.\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "(Un ta ohtra Wahrdz bija Eliëfers, jo fazzija\nwiꞥſch, manna Tehwa Deews irr man pa-\nPaligu bijis, un irr mann isrähwis no Waraü̅\nSohbina. 2. Mohs: Gr: 18, 4.)\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Un ilgu Laiku pehz to no-\nmirre tas Egipternu Kehniſsch/un-\ntee Israëka Behrni nopuhtehs/un-\nbrehze pahr ſcho Kalpoſchann/un-\nwinnu Brehkschana uſkahpe no-\nSemmes pee Deewa.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Un Deetws dsirdeja wiꞥno-\nNopuhtschannu/ un Deews atgah-\ndajahs ſuwas Derribas ar Ah-\nbräimu/Jhsääku un Jehkabu.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un Deews uſluhke tohs\nIsraëka Behrnis/un Deews neh-\nme to wehrâ.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Mohsus gannaſawa Tehwotscha Jetrus Awis:\nTohp no Deewa is deggoscha Krubma-\nzaur weenu Exgeli aizinahts tohs Israëta-\nBehrnis no Egiptesistwest-2. Leedsahs pa-\npreeſch : 11. Bet dabbu pehz no Deewa-\nfo wiꞥnam bij runnaht pee teem Israëfa-\nBehrneem/un preeſch Waraü̅s : 13/18.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "N Mohsus gannija Je-\ntrus fawa Tehwotscha-\nta Midijanas augsta-\nKunga Awis / un wiꞥſch odſinne-\ntahs Awis pakkat tahs Tuſfini-\nbas/ un nahze pee to Deewu Kal-\nnun Oreb.\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Un ta KUNGA Engelis-\nrahdijahs wiꞥnam Uggunu Leeſ-\nmâ/ no weena Ehrſchku-Krub-\nma/ un wiꞥſch ſkattijahs / un-\nraugt / tas Ehrſchku-Krubms\n"
    }
  ],
